+/// ```
 #[inline]
 pub fn read_recover<T>(rwlock: &RwLock<T>) -> RwLockReadGuard<'_, T> {
-    rwlock
-        .read()
-        .unwrap_or_else(std::sync::PoisonError::into_inner)
+    rwlock.read().unwrap_or_else(std::sync::PoisonError::into_inner)
 }

